import React, { useState, useEffect, useMemo, useCallback } from "react";
import {
  Plus,
  Search,
  Edit2,
  Trash2,
  Save,
  X,
  StickyNote,
  Star,
  Archive,
  Tag,
  Clock,
  Download,
  Upload,
  Grid,
  List,
  Pin,
  Copy,
  Share2,
  Palette,
  CheckSquare,
  Moon,
  Sun,
  Menu,
  BarChart3,
  Folder,
  LogOut,
  History,
  Bell,
  Trash,
  RotateCcw,
  Sparkles,
  FileText,
  Activity,
  RefreshCw,
  Filter,
  Zap,
} from "lucide-react";
import { useAuth } from "./context/AuthContext";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import CustomCategories from "./components/CustomCategories";
import Templates from "./components/Templates";
import { API_URL } from "./config/env";

const NotesApp = () => {
  const { getAuthHeaders, logout, user } = useAuth();
  const [notes, setNotes] = useState([]);
  const [trashNotes, setTrashNotes] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [isCreating, setIsCreating] = useState(false);
  const [editingNote, setEditingNote] = useState(null);
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState("grid");
  const [filterMode, setFilterMode] = useState("all");
  const [sortMode, setSortMode] = useState("date");
  const [darkMode, setDarkMode] = useState(false);
  const [showStats, setShowStats] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [showTrash, setShowTrash] = useState(false);
  const [showVersions, setShowVersions] = useState(false);
  const [noteVersions, setNoteVersions] = useState([]);
  const [selectedNoteForVersions, setSelectedNoteForVersions] = useState(null);
  const [showShareModal, setShowShareModal] = useState(false);
  const [noteToShare, setNoteToShare] = useState(null);
  const [shareEmail, setShareEmail] = useState("");
  const [sharePermission, setSharePermission] = useState("read");
  const [customCategories, setCustomCategories] = useState([]);
  const [showTemplates, setShowTemplates] = useState(false);
  const [showActivityLog, setShowActivityLog] = useState(false);
  const [activities, setActivities] = useState([]);
  const [showThemeSettings, setShowThemeSettings] = useState(false);
  const [userSettings, setUserSettings] = useState(null);
  const [syncStatus, setSyncStatus] = useState({ syncing: false, lastSync: null });
  const [selectedNotes, setSelectedNotes] = useState([]);
 
  const colors = useMemo(
    () => [
      { name: "Vàng nhạt", value: "#FFE4B5" },
      { name: "Xanh dương", value: "#B5E4FF" },
      { name: "Hồng", value: "#FFB5E4" },
      { name: "Xanh lá", value: "#B5FFE4" },
      { name: "Tím", value: "#E4B5FF" },
      { name: "Cam", value: "#FFD4B5" },
      { name: "Xám", value: "#E0E0E0" },
      { name: "Đỏ nhạt", value: "#FFB5B5" },
      { name: "Xanh navy", value: "#B5D4FF" },
      { name: "Hồng đậm", value: "#FFB5D4" },
    ],
    []
  );

  const defaultCategories = useMemo(
    () => [
      { id: "all", name: "Tất cả", icon: <Folder size={18} /> },
      { id: "personal", name: "Cá nhân", icon: <StickyNote size={18} /> },
      { id: "work", name: "Công việc", icon: <BarChart3 size={18} /> },
      { id: "study", name: "Học tập", icon: <CheckSquare size={18} /> },
      { id: "ideas", name: "Ý tưởng", icon: <Star size={18} /> },
    ],
    []
  );

  const categories = useMemo(() => {
    const custom = customCategories.map((cat) => ({
      id: cat._id,
      name: cat.name,
      icon: <Folder size={18} style={{ color: cat.color }} />,
      isCustom: true,
    }));
    return [...defaultCategories, ...custom];
  }, [defaultCategories, customCategories]);

  // Định nghĩa fetchNotes và fetchTrash TRƯỚC khi sử dụng trong useEffect
  const fetchNotes = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/notes`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setNotes(Array.isArray(data.notes) ? data.notes : []);
      setLoading(false);
    } catch (error) {
      console.error("Lỗi khi tải notes:", error);
      setLoading(false);
    }
  }, [getAuthHeaders]);

  const fetchTrash = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/notes/trash/all`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setTrashNotes(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Lỗi khi tải thùng rác:", error);
    }
  }, [getAuthHeaders]);

  const fetchCustomCategories = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/categories`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setCustomCategories(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Lỗi khi tải categories:", error);
    }
  }, [getAuthHeaders]);

  const fetchActivities = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/activities?limit=50`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setActivities(Array.isArray(data.activities) ? data.activities : []);
    } catch (error) {
      console.error("Lỗi khi tải activities:", error);
    }
  }, [getAuthHeaders]);

  const fetchUserSettings = useCallback(async () => {
    try {
      const response = await fetch(`${API_URL}/settings`, {
        headers: getAuthHeaders(),
      });
      const data = await response.json();
      setUserSettings(data);
    } catch (error) {
      console.error("Lỗi khi tải settings:", error);
    }
  }, [getAuthHeaders]);

  // AI suggestions feature disabled for now


  useEffect(() => {
    const init = async () => {
      await fetchNotes();
      await fetchCustomCategories();
      await fetchUserSettings();
      const savedDarkMode = localStorage.getItem("darkMode") === "true";
      setDarkMode(savedDarkMode);
      
      // Initialize sync
      initializeSync();
    };
    init();
  }, [fetchNotes, fetchCustomCategories, fetchUserSettings, initializeSync]);

 
  // Auto sync every 30 seconds (only when online)
  useEffect(() => {
    if (!navigator.onLine) return;
    
    const syncInterval = setInterval(() => {
      performSync();
    }, 30000);

    return () => clearInterval(syncInterval);
  }, [performSync]);

  useEffect(() => {
    if (showTrash) {
      fetchTrash();
    }
  }, [showTrash, fetchTrash]);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add("dark");
    } else {
      document.documentElement.classList.remove("dark");
    }
    localStorage.setItem("darkMode", darkMode);
  }, [darkMode]);

  // Apply custom theme
  useEffect(() => {
    if (userSettings?.customTheme) {
      const theme = userSettings.customTheme;
      const root = document.documentElement;
      root.style.setProperty("--primary-color", theme.primaryColor || "#3b82f6");
      root.style.setProperty("--secondary-color", theme.secondaryColor || "#8b5cf6");
      const fontSizeMap = { small: "14px", medium: "16px", large: "18px" };
      root.style.setProperty("--font-size", fontSizeMap[theme.fontSize] || "16px");
    } else {
      // Reset về mặc định nếu chưa có theme
      const root = document.documentElement;
      root.style.setProperty("--primary-color", "#3b82f6");
      root.style.setProperty("--secondary-color", "#8b5cf6");
      root.style.setProperty("--font-size", "16px");
    }
  }, [userSettings]);

  // Tạo note mặc định khi mở modal tạo
  const defaultNewNote = useMemo(
    () => ({
      title: "",
      content: "",
      color: "#FFE4B5",
      tags: [],
      isFavorite: false,
      isArchived: false,
      isPinned: false,
      category: "personal",
      checklist: [],
      isMarkdown: false,
      reminder: null,
    }),
    []
  );

  // API helpers nhận note từ modal
  const createNoteFromModal = useCallback(async (noteToCreate) => {
    if (!noteToCreate.title.trim()) {
      alert("Vui lòng nhập tiêu đề!");
      return;
    }
    try {
      const response = await fetch(`${API_URL}/notes`, {
        method: "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(noteToCreate),
      });
      const note = await response.json();
      setNotes((prev) => [note, ...prev]);
      setIsCreating(false);
      // Refresh categories sau khi tạo note
      await fetchCustomCategories();
    } catch (error) {
      console.error("Lỗi khi tạo note:", error);
      alert("Không thể tạo ghi chú. Vui lòng kiểm tra kết nối backend!");
    }
  }, [getAuthHeaders, fetchCustomCategories]);

  const updateNoteFromModal = useCallback(async (noteToUpdate) => {
    if (!noteToUpdate.title.trim()) {
      alert("Vui lòng nhập tiêu đề!");
      return;
    }
    try {
      const response = await fetch(`${API_URL}/notes/${noteToUpdate._id}`, {
        method: "PUT",
        headers: getAuthHeaders(),
        body: JSON.stringify(noteToUpdate),
      });
      const updatedNote = await response.json();
      setNotes((prev) =>
        prev.map((n) => (n._id === updatedNote._id ? updatedNote : n))
      );
      setEditingNote(null);
    } catch (error) {
      console.error("Lỗi khi cập nhật note:", error);
      alert("Không thể cập nhật ghi chú!");
    }
  }, [getAuthHeaders]);

  const deleteNote = useCallback(async (id) => {
    if (!window.confirm("Bạn có chắc muốn xóa ghi chú này?")) return;

    try {
      await fetch(`${API_URL}/notes/${id}`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });
      setNotes((prev) => prev.filter((n) => n._id !== id));
      if (showTrash) {
        await fetchTrash();
      }
    } catch (error) {
      console.error("Lỗi khi xóa note:", error);
    }
  }, [getAuthHeaders, showTrash, fetchTrash]);

  const restoreNote = useCallback(async (id) => {
    try {
      const response = await fetch(`${API_URL}/notes/${id}/restore`, {
        method: "POST",
        headers: getAuthHeaders(),
      });
      const note = await response.json();
      setTrashNotes((prev) => prev.filter((n) => n._id !== id));
      setNotes((prev) => [note, ...prev]);
    } catch (error) {
      console.error("Lỗi khi khôi phục:", error);
    }
  }, [getAuthHeaders]);

  const deletePermanently = useCallback(async (id) => {
    if (!window.confirm("Bạn có chắc muốn xóa VĨNH VIỄN? Hành động này không thể hoàn tác!")) return;

    try {
      await fetch(`${API_URL}/notes/${id}/permanent`, {
        method: "DELETE",
        headers: getAuthHeaders(),
      });
      setTrashNotes((prev) => prev.filter((n) => n._id !== id));
    } catch (error) {
      console.error("Lỗi khi xóa vĩnh viễn:", error);
    }
  }, [getAuthHeaders]);

  const toggleNoteSelection = useCallback((noteId) => {
    setSelectedNotes(prev => 
      prev.includes(noteId) 
        ? prev.filter(id => id !== noteId)
        : [...prev, noteId]
    );
  }, []);

  const selectAllNotes = useCallback(() => {
    setSelectedNotes(filteredNotes.map(note => note._id));
  }, [filteredNotes]);

  const deselectAllNotes = useCallback(() => {
    setSelectedNotes([]);
  }, []);

  const deleteSelectedNotes = useCallback(async () => {
    if (selectedNotes.length === 0) return;
    
    const confirmMsg = `Bạn có chắc muốn xóa ${selectedNotes.length} ghi chú đã chọn?`;
    if (!window.confirm(confirmMsg)) return;

    try {
      await Promise.all(
        selectedNotes.map(id => 
          fetch(`${API_URL}/notes/${id}`, {
            method: "DELETE",
            headers: getAuthHeaders(),
          })
        )
      );
      
      setNotes(prev => prev.filter(n => !selectedNotes.includes(n._id)));
      setSelectedNotes([]);
      
      if (showTrash) {
        await fetchTrash();
      }
    } catch (error) {
      console.error("Lỗi khi xóa notes:", error);
      alert("Có lỗi xảy ra khi xóa ghi chú!");
    }
  }, [selectedNotes, getAuthHeaders, showTrash, fetchTrash]);

  const duplicateNote = useCallback(async (note) => {
    const newNote = { ...note };
    delete newNote._id;
    newNote.title = `${note.title} (Copy)`;

    try {
      const response = await fetch(API_URL, {
        method: "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify(newNote),
      });
      const created = await response.json();
      setNotes((prev) => [created, ...prev]);
    } catch (error) {
      console.error("Lỗi:", error);
    }
  }, [getAuthHeaders]);

  const fetchVersions = useCallback(async (noteId) => {
    try {
      const response = await fetch(`${API_URL}/notes/${noteId}/versions`, {
        headers: getAuthHeaders(),
      });
      const versions = await response.json();
      setNoteVersions(versions);
      setSelectedNoteForVersions(noteId);
      setShowVersions(true);
    } catch (error) {
      console.error("Lỗi khi tải versions:", error);
    }
  }, [getAuthHeaders]);

  const restoreVersion = useCallback(async (noteId, versionId) => {
    try {
      const response = await fetch(`${API_URL}/notes/${noteId}/versions/${versionId}/restore`, {
        method: "POST",
        headers: getAuthHeaders(),
      });
      const restoredNote = await response.json();
      setNotes((prev) =>
        prev.map((n) => (n._id === restoredNote._id ? restoredNote : n))
      );
      setShowVersions(false);
      alert("Đã khôi phục phiên bản cũ!");
    } catch (error) {
      console.error("Lỗi khi khôi phục version:", error);
    }
  }, [getAuthHeaders]);

  const shareNote = useCallback(async (note, email, permission) => {
    try {
      const response = await fetch(`${API_URL}/shares`, {
        method: "POST",
        headers: getAuthHeaders(),
        body: JSON.stringify({ noteId: note._id, email, permission }),
      });
      if (response.ok) {
        alert("Đã chia sẻ ghi chú!");
        setShowShareModal(false);
        setShareEmail("");
      } else {
        const data = await response.json();
        alert(data.error || "Lỗi khi chia sẻ");
      }
    } catch (error) {
      console.error("Lỗi khi chia sẻ:", error);
      alert("Lỗi khi chia sẻ ghi chú");
    }
  }, [getAuthHeaders]);

  const togglePin = useCallback(async (note) => {
    try {
      const updatedNote = { ...note, isPinned: !note.isPinned };
      const response = await fetch(`${API_URL}/notes/${note._id}`, {
        method: "PUT",
        headers: getAuthHeaders(),
        body: JSON.stringify(updatedNote),
      });
      const data = await response.json();
      setNotes((prev) => prev.map((n) => (n._id === data._id ? data : n)));
    } catch (error) {
      console.error("Lỗi:", error);
    }
  }, [getAuthHeaders]);

  const toggleFavorite = useCallback(async (note) => {
    try {
      const updatedNote = { ...note, isFavorite: !note.isFavorite };
      const response = await fetch(`${API_URL}/notes/${note._id}`, {
        method: "PUT",
        headers: getAuthHeaders(),
        body: JSON.stringify(updatedNote),
      });
      const data = await response.json();
      setNotes((prev) => prev.map((n) => (n._id === data._id ? data : n)));
    } catch (error) {
      console.error("Lỗi:", error);
    }
  }, [getAuthHeaders]);

  const toggleArchive = useCallback(async (note) => {
    try {
      const updatedNote = { ...note, isArchived: !note.isArchived };
      const response = await fetch(`${API_URL}/notes/${note._id}`, {
        method: "PUT",
        headers: getAuthHeaders(),
        body: JSON.stringify(updatedNote),
      });
      const data = await response.json();
      setNotes((prev) => prev.map((n) => (n._id === data._id ? data : n)));
    } catch (error) {
      console.error("Lỗi:", error);
    }
  }, [getAuthHeaders]);

  const exportNotes = useCallback(() => {
    const dataStr = JSON.stringify(notes, null, 2);
    const dataBlob = new Blob([dataStr], { type: "application/json" });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `notes-backup-${
      new Date().toISOString().split("T")[0]
    }.json`;
    link.click();
    URL.revokeObjectURL(url);
  }, [notes]);

  const importNotes = useCallback(
    (event) => {
      const file = event.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
          const importedNotes = JSON.parse(e.target.result);
          if (!Array.isArray(importedNotes)) {
            alert("File không hợp lệ!");
            return;
          }
          for (const note of importedNotes) {
            const clone = { ...note };
            delete clone._id;
            await fetch(API_URL, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify(clone),
            });
          }
          await fetchNotes();
          alert("Đã nhập ghi chú thành công!");
        } catch (error) {
          console.error(error);
          alert("Lỗi khi nhập file!");
        }
      };
      reader.readAsText(file);
      // reset input để lần sau vẫn onChange được file giống nhau
      event.target.value = "";
    },
    [fetchNotes]
  );


  const getStats = useCallback(() => {
    // Tính stats cho default categories
    const defaultStats = defaultCategories.slice(1).map((cat) => ({
      name: cat.name,
      count: notes.filter((n) => n.category === cat.id).length,
    }));
    
    // Tính stats cho custom categories
    const customStats = customCategories.map((cat) => ({
      name: cat.name,
      count: notes.filter((n) => n.category === cat._id || n.category === cat.name).length,
    }));
    
    return {
      total: notes.length,
      pinned: notes.filter((n) => n.isPinned).length,
      favorites: notes.filter((n) => n.isFavorite).length,
      archived: notes.filter((n) => n.isArchived).length,
      byCategory: [...defaultStats, ...customStats],
    };
  }, [notes, defaultCategories, customCategories]);

  // Smart Filters với logic nâng cao
  const filteredNotes = useMemo(() => {
    let filtered = [...notes];

    // Smart search - tìm kiếm thông minh
    if (searchTerm.trim()) {
      const searchLower = searchTerm.toLowerCase();
      filtered = filtered.filter((note) => {
        // Tìm trong title
        if (note.title?.toLowerCase().includes(searchLower)) return true;
        // Tìm trong content
        if (note.content?.toLowerCase().includes(searchLower)) return true;
        // Tìm trong tags
        if (note.tags?.some((tag) => tag.toLowerCase().includes(searchLower))) return true;
        // Tìm trong checklist
        if (note.checklist?.some((item) => item.text?.toLowerCase().includes(searchLower))) return true;
        return false;
      });
    }

    // Filter theo category (hỗ trợ custom categories)
    if (selectedCategory !== "all") {
      filtered = filtered.filter((n) => {
        // Kiểm tra cả default categories và custom categories
        if (n.category === selectedCategory) return true;
        // Nếu selectedCategory là custom category ID, kiểm tra theo _id
        const customCat = customCategories.find((c) => c._id === selectedCategory);
        if (customCat) {
          // Có thể note.category lưu _id hoặc name của custom category
          return n.category === customCat._id || n.category === customCat.name;
        }
        return false;
      });
    }

    // Filter theo mode
    if (filterMode === "favorites") {
      filtered = filtered.filter((n) => n.isFavorite);
    } else if (filterMode === "archived") {
      filtered = filtered.filter((n) => n.isArchived);
    } else if (filterMode === "active") {
      filtered = filtered.filter((n) => !n.isArchived);
    }

    // Filter theo reminder (notes có reminder sắp tới)
    if (filterMode === "reminders") {
      const now = new Date();
      filtered = filtered.filter((n) => {
        if (!n.reminder) return false;
        const reminderDate = new Date(n.reminder);
        return reminderDate > now && !n.reminderSent;
      });
    }

    // Sort
    if (sortMode === "date") {
      filtered.sort((a, b) => {
        if (a.isPinned && !b.isPinned) return -1;
        if (!a.isPinned && b.isPinned) return 1;
        return new Date(b.createdAt) - new Date(a.createdAt);
      });
    } else if (sortMode === "title") {
      filtered.sort((a, b) => a.title.localeCompare(b.title));
    } else if (sortMode === "color") {
      filtered.sort((a, b) => (a.color || "").localeCompare(b.color || ""));
    } else if (sortMode === "updated") {
      filtered.sort((a, b) => {
        const aUpdated = new Date(a.updatedAt || a.createdAt);
        const bUpdated = new Date(b.updatedAt || b.createdAt);
        return bUpdated - aUpdated;
      });
    }

    return filtered;
  }, [notes, searchTerm, selectedCategory, filterMode, sortMode, customCategories]);

  // NEW: cập nhật nhanh checklist item ngay từ NoteCard
  const updateChecklistItem = useCallback(async (note, index, checked) => {
    try {
      const newChecklist = [...(note.checklist || [])];
      if (!newChecklist[index]) return;
      newChecklist[index] = { ...newChecklist[index], checked };

      const updatedNote = { ...note, checklist: newChecklist };
      const res = await fetch(`${API_URL}/notes/${note._id}`, {
        method: "PUT",
        headers: getAuthHeaders(),
        body: JSON.stringify(updatedNote),
      });
      const data = await res.json();

      // cập nhật state cục bộ để UI phản hồi ngay
      setNotes((prev) => prev.map((n) => (n._id === data._id ? data : n)));
    } catch (e) {
      console.error("Lỗi cập nhật checklist:", e);
    }
  }, [getAuthHeaders]);

  // Optional: trạng thái xem thêm/thu gọn checklist theo từng note
  const [expandedChecklistIds, setExpandedChecklistIds] = useState({});
  const toggleExpandChecklist = useCallback((id) => {
    setExpandedChecklistIds((prev) => ({ ...prev, [id]: !prev[id] }));
  }, []);

  const NoteCard = React.memo(({ note }) => {
    const isExpanded = !!expandedChecklistIds[note._id];
    const itemsToShow =
      isExpanded || !note.checklist || note.checklist.length <= 3
        ? note.checklist || []
        : note.checklist.slice(0, 3);

    return (
      <div
        className={`group relative rounded-2xl p-6 shadow-lg hover:shadow-2xl transition-all duration-300 ${
          viewMode === "grid" ? "transform hover:-translate-y-1" : ""
        } ${note.isPinned ? "ring-2 ring-blue-500" : ""}`}
        style={{ backgroundColor: note.color }}
      >
        {note.isPinned && (
          <div className="absolute -top-2 -right-2 bg-blue-500 text-white rounded-full p-2 shadow-lg">
            <Pin size={14} />
          </div>
        )}

        {/* Selection checkbox */}
        {!showTrash && (
          <div className="absolute top-3 left-3 z-10">
            <input
              type="checkbox"
              checked={selectedNotes.includes(note._id)}
              onChange={(e) => {
                e.stopPropagation();
                toggleNoteSelection(note._id);
              }}
              className="w-5 h-5 cursor-pointer rounded border-2 border-gray-400 checked:bg-blue-500 checked:border-blue-500 transition-all"
              title="Chọn ghi chú"
            />
          </div>
        )}

        <div className="absolute top-3 right-3 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
          <button
            onClick={() => togglePin(note)}
            className="p-2 bg-white bg-opacity-80 rounded-full shadow-md hover:bg-opacity-100 transition-all"
            title="Ghim ghi chú"
          >
            <Pin
              size={14}
              className={note.isPinned ? "text-blue-600" : "text-gray-400"}
            />
          </button>
          <button
            onClick={() => toggleFavorite(note)}
            className="p-2 bg-white bg-opacity-80 rounded-full shadow-md hover:bg-opacity-100 transition-all"
            title="Yêu thích"
          >
            <Star
              size={14}
              className={
                note.isFavorite
                  ? "text-yellow-500 fill-yellow-500"
                  : "text-gray-400"
              }
            />
          </button>
        </div>

        <h3 className="text-xl font-bold mb-3 pr-20 text-gray-800">
          {note.title}
        </h3>

        {note.checklist && note.checklist.length > 0 && (
          <div className="mb-3 space-y-2">
            {itemsToShow.map((item, idx) => {
              // Tính index thực tế trong note.checklist
              const indexInNote = isExpanded || note.checklist.length <= 3 
                ? idx 
                : idx; // Khi không expanded, itemsToShow đã là slice(0,3), nên idx chính là index trong slice
              return (
                <label
                  key={idx}
                  className="flex items-center gap-2 cursor-pointer"
                >
                  <input
                    type="checkbox"
                    checked={item.checked}
                    onChange={(e) =>
                      updateChecklistItem(note, indexInNote, e.target.checked)
                    }
                    className="w-4 h-4"
                  />
                  <span
                    className={`text-sm ${
                      item.checked
                        ? "line-through text-gray-500"
                        : "text-gray-700"
                    }`}
                  >
                    {item.text}
                  </span>
                </label>
              );
            })}
            {note.checklist.length > 3 && (
              <button
                className="text-xs text-blue-700 underline"
                onClick={() => toggleExpandChecklist(note._id)}
              >
                {isExpanded
                  ? "Thu gọn"
                  : `Xem thêm +${note.checklist.length - 3} mục`}
              </button>
            )}
          </div>
        )}

        <div className="mb-3 line-clamp-3">
          {note.isMarkdown ? (
            <div className="prose prose-sm dark:prose-invert max-w-none">
              <ReactMarkdown remarkPlugins={[remarkGfm]}>
                {note.content}
              </ReactMarkdown>
            </div>
          ) : (
            <p className="text-gray-700 whitespace-pre-wrap">{note.content}</p>
          )}
        </div>

        {note.reminder && (
          <div className="mb-3 flex items-center gap-2 text-xs text-orange-700 bg-orange-100 bg-opacity-60 px-2 py-1 rounded-full">
            <Bell size={12} />
            Nhắc: {new Date(note.reminder).toLocaleString("vi-VN")}
          </div>
        )}

        {note.tags && note.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mb-3">
            {note.tags.slice(0, 3).map((tag, idx) => (
              <span
                key={idx}
                className="px-2 py-1 bg-white bg-opacity-60 rounded-full text-xs font-semibold text-gray-700"
              >
                #{tag}
              </span>
            ))}
            {note.tags.length > 3 && (
              <span className="px-2 py-1 bg-white bg-opacity-60 rounded-full text-xs font-semibold text-gray-700">
                +{note.tags.length - 3}
              </span>
            )}
          </div>
        )}

        <div className="flex items-center justify-between text-xs text-gray-600 mb-3">
          <div className="flex items-center gap-1">
            <Clock size={12} />
            {note.createdAt
              ? new Date(note.createdAt).toLocaleDateString("vi-VN", {
                  day: "2-digit",
                  month: "2-digit",
                  year: "numeric",
                })
              : ""}
          </div>
          <span className="px-2 py-1 bg-white bg-opacity-60 rounded-full text-xs font-semibold">
            {categories.find((c) => c.id === note.category)?.name || "Cá nhân"}
          </span>
        </div>

        <div className="grid grid-cols-6 gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
          <button
            onClick={() => setEditingNote(note)}
            className="flex items-center justify-center p-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors"
            title="Sửa"
          >
            <Edit2 size={14} />
          </button>
          <button
            onClick={() => duplicateNote(note)}
            className="flex items-center justify-center p-2 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors"
            title="Sao chép"
          >
            <Copy size={14} />
          </button>
          <button
            onClick={() => {
              setNoteToShare(note);
              setShowShareModal(true);
            }}
            className="flex items-center justify-center p-2 bg-purple-500 text-white rounded-lg hover:bg-purple-600 transition-colors"
            title="Chia sẻ"
          >
            <Share2 size={14} />
          </button>
          <button
            onClick={() => fetchVersions(note._id)}
            className="flex items-center justify-center p-2 bg-indigo-500 text-white rounded-lg hover:bg-indigo-600 transition-colors"
            title="Lịch sử"
          >
            <History size={14} />
          </button>
          <button
            onClick={() => toggleArchive(note)}
            className="flex items-center justify-center p-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors"
            title={note.isArchived ? "Bỏ lưu trữ" : "Lưu trữ"}
          >
            <Archive size={14} />
          </button>
          <button
            onClick={() => deleteNote(note._id)}
            className="flex items-center justify-center p-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
            title="Xóa"
          >
            <Trash2 size={14} />
          </button>
        </div>
      </div>
    );
  });

  const NoteModal = React.memo(
    ({ initialNote, onSave, onClose, title, colors, categories, customCategories = [] }) => {
      const { getAuthHeaders } = useAuth();
      
      // Combine default and custom categories for select (chỉ lấy default categories, custom đã có trong categories)
      const allCategories = React.useMemo(() => {
        // Chỉ lấy default categories (không bao gồm custom vì custom đã được merge vào categories ở component cha)
        const defaultCats = categories.slice(1).filter((cat) => !cat.isCustom);
        // Thêm custom categories từ prop
        const customCats = customCategories.map((cat) => ({ id: cat._id, name: cat.name }));
        return [...defaultCats, ...customCats];
      }, [categories, customCategories]);
      const [localNote, setLocalNote] = useState(() => ({ ...initialNote }));
      const [localTagInput, setLocalTagInput] = useState("");
      const [localChecklistInput, setLocalChecklistInput] = useState("");
      const [isMarkdownMode, setIsMarkdownMode] = useState(initialNote.isMarkdown || false);
      const [showPreview, setShowPreview] = useState(false);
      const [reminderDate, setReminderDate] = useState(
        initialNote.reminder ? new Date(initialNote.reminder).toISOString().slice(0, 16) : ""
      );

      // Đồng bộ khi initialNote thay đổi (ví dụ khi mở modal edit note mới)
      useEffect(() => {
        setLocalNote({ ...initialNote });
        setLocalTagInput("");
        setLocalChecklistInput("");
        setIsMarkdownMode(initialNote.isMarkdown || false);
        setShowPreview(false);
        setReminderDate(
          initialNote.reminder ? new Date(initialNote.reminder).toISOString().slice(0, 16) : ""
        );
      }, [initialNote]);

      const addTag = useCallback(() => {
        const v = localTagInput.trim();
        if (!v) return;
        setLocalNote((prev) => ({
          ...prev,
          tags: [...(prev.tags || []), v],
        }));
        setLocalTagInput("");
      }, [localTagInput]);

      const removeTag = useCallback((tagToRemove) => {
        setLocalNote((prev) => ({
          ...prev,
          tags: (prev.tags || []).filter((t) => t !== tagToRemove),
        }));
      }, []);

      const addChecklistItem = useCallback(() => {
        const v = localChecklistInput.trim();
        if (!v) return;
        setLocalNote((prev) => ({
          ...prev,
          checklist: [...(prev.checklist || []), { text: v, checked: false }],
        }));
        setLocalChecklistInput("");
      }, [localChecklistInput]);

      const toggleChecklistItem = useCallback((index) => {
        setLocalNote((prev) => {
          const list = [...(prev.checklist || [])];
          list[index] = { ...list[index], checked: !list[index].checked };
          return { ...prev, checklist: list };
        });
      }, []);

      const removeChecklistItem = useCallback((index) => {
        setLocalNote((prev) => {
          const list = (prev.checklist || []).filter((_, i) => i !== index);
          return { ...prev, checklist: list };
        });
      }, []);

      return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl max-w-4xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800 dark:text-white">
                {title}
              </h2>
              <button
                onClick={onClose}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2 space-y-4">
                <div className="flex gap-2">
                  <input
                    type="text"
                    placeholder="Tiêu đề ghi chú..."
                    value={localNote.title}
                    onChange={(e) =>
                      setLocalNote({ ...localNote, title: e.target.value })
                    }
                    className="flex-1 px-4 py-3 text-xl font-semibold border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors"
                  />
                  <button
                    type="button"
                    onClick={async () => {
                      if (!localNote.content.trim()) return;
                      try {
                        const response = await fetch(`${API_URL}/ai/suggest-title`, {
                          method: "POST",
                          headers: getAuthHeaders(),
                          body: JSON.stringify({ content: localNote.content }),
                        });
                        const data = await response.json();
                        if (data.title) {
                          setLocalNote({ ...localNote, title: data.title });
                        }
                      } catch (error) {
                        console.error("Lỗi AI:", error);
                      }
                    }}
                    className="px-4 py-3 bg-purple-500 text-white rounded-xl hover:bg-purple-600 transition-colors flex items-center gap-2"
                    title="Gợi ý tiêu đề bằng AI"
                  >
                    <Sparkles size={20} />
                  </button>
                  <button
                    type="button"
                    onClick={async () => {
                      try {
                        const response = await fetch(`${API_URL}/ai/suggest-actions`, {
                          method: "POST",
                          headers: getAuthHeaders(),
                          body: JSON.stringify({
                            noteContent: localNote.content,
                            noteTitle: localNote.title,
                            tags: localNote.tags,
                            category: localNote.category,
                          }),
                        });
                        const data = await response.json();
                        if (data.suggestions && data.suggestions.length > 0) {
                          const suggestions = data.suggestions.map((s) => s.message).join("\n");
                          alert(`Gợi ý:\n\n${suggestions}`);
                        }
                      } catch (error) {
                        console.error("Lỗi AI:", error);
                      }
                    }}
                    className="px-4 py-3 bg-indigo-500 text-white rounded-xl hover:bg-indigo-600 transition-colors flex items-center gap-2"
                    title="Gợi ý hành động"
                  >
                    <Zap size={20} />
                  </button>
                </div>

                <div className="mb-2 flex gap-2">
                  <button
                    onClick={() => setIsMarkdownMode(!isMarkdownMode)}
                    className={`px-3 py-1 rounded-lg text-sm font-semibold transition-colors ${
                      isMarkdownMode
                        ? "bg-blue-500 text-white"
                        : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300"
                    }`}
                  >
                    Markdown
                  </button>
                  {isMarkdownMode && (
                    <button
                      onClick={() => setShowPreview(!showPreview)}
                      className="px-3 py-1 rounded-lg text-sm font-semibold bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
                    >
                      {showPreview ? "Chỉnh sửa" : "Xem trước"}
                    </button>
                  )}
                </div>

                <div className="relative">
                  {showPreview && isMarkdownMode ? (
                    <div className="w-full px-4 py-3 h-64 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 rounded-xl overflow-y-auto prose dark:prose-invert max-w-none">
                      <ReactMarkdown remarkPlugins={[remarkGfm]}>
                        {localNote.content}
                      </ReactMarkdown>
                    </div>
                  ) : (
                    <>
                      <textarea
                        placeholder={isMarkdownMode ? "Viết markdown..." : "Nội dung ghi chú..."}
                        value={localNote.content}
                        onChange={(e) =>
                          setLocalNote({ ...localNote, content: e.target.value })
                        }
                        className="w-full px-4 py-3 h-64 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none resize-none transition-colors font-mono"
                      />
                      {localNote.content.trim() && (
                        <div className="absolute bottom-2 right-2 flex gap-2">
                          <button
                            type="button"
                            onClick={async () => {
                              try {
                                const response = await fetch(`${API_URL}/ai/summarize`, {
                                  method: "POST",
                                  headers: getAuthHeaders(),
                                  body: JSON.stringify({ content: localNote.content }),
                                });
                                const data = await response.json();
                                if (data.summary) {
                                  alert(`Tóm tắt:\n\n${data.summary}`);
                                }
                              } catch (error) {
                                console.error("Lỗi AI:", error);
                              }
                            }}
                            className="px-3 py-1 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors text-sm flex items-center gap-1"
                            title="Tóm tắt nội dung"
                          >
                            <Sparkles size={14} />
                            Tóm tắt
                          </button>
                          <button
                            type="button"
                            onClick={async () => {
                              try {
                                const response = await fetch(`${API_URL}/ai/generate-checklist`, {
                                  method: "POST",
                                  headers: getAuthHeaders(),
                                  body: JSON.stringify({ content: localNote.content }),
                                });
                                const data = await response.json();
                                if (data.checklist && data.checklist.length > 0) {
                                  setLocalNote({
                                    ...localNote,
                                    checklist: [...(localNote.checklist || []), ...data.checklist],
                                  });
                                }
                              } catch (error) {
                                console.error("Lỗi AI:", error);
                              }
                            }}
                            className="px-3 py-1 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors text-sm flex items-center gap-1"
                            title="Tạo checklist từ nội dung"
                          >
                            <Sparkles size={14} />
                            Checklist
                          </button>
                        </div>
                      )}
                    </>
                  )}
                </div>

                <div>
                  <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-2">
                    <CheckSquare size={16} />
                    Danh sách công việc:
                  </p>
                  <div className="flex gap-2 mb-2">
                    <input
                      type="text"
                      placeholder="Thêm công việc..."
                      value={localChecklistInput}
                      onChange={(e) => setLocalChecklistInput(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.isComposing) return;
                        if (e.key === "Enter") {
                          e.preventDefault();
                          addChecklistItem();
                        }
                      }}
                      className="flex-1 px-3 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none"
                    />
                    <button
                      onClick={addChecklistItem}
                      className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold"
                    >
                      Thêm
                    </button>
                  </div>
                  <div className="space-y-2 max-h-40 overflow-y-auto">
                    {localNote.checklist &&
                      localNote.checklist.map((item, idx) => (
                        <div
                          key={idx}
                          className="flex items-center gap-2 bg-gray-50 dark:bg-gray-700 p-2 rounded-lg"
                        >
                          <input
                            type="checkbox"
                            checked={item.checked}
                            onChange={() => toggleChecklistItem(idx)}
                            className="w-5 h-5"
                          />
                          <span
                            className={`flex-1 ${
                              item.checked
                                ? "line-through text-gray-500"
                                : "text-gray-700 dark:text-gray-300"
                            }`}
                          >
                            {item.text}
                          </span>
                          <button
                            onClick={() => removeChecklistItem(idx)}
                            className="text-red-500 hover:text-red-700"
                          >
                            <X size={16} />
                          </button>
                        </div>
                      ))}
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div>
                  <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                    Danh mục:
                  </p>
                  <select
                    value={localNote.category}
                    onChange={(e) =>
                      setLocalNote({ ...localNote, category: e.target.value })
                    }
                    className="w-full px-3 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none"
                  >
                    {allCategories.map((cat) => (
                      <option key={cat.id} value={cat.id}>
                        {cat.name}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-2">
                    <Tag size={16} />
                    Thẻ (Tags):
                  </p>
                  <div className="flex gap-2 mb-2">
                    <input
                      type="text"
                      placeholder="Thêm thẻ..."
                      value={localTagInput}
                      onChange={(e) => setLocalTagInput(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.isComposing) return;
                        if (e.key === "Enter") {
                          e.preventDefault();
                          addTag();
                        }
                      }}
                      className="flex-1 px-3 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none"
                    />
                    <button
                      onClick={addTag}
                      className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors font-semibold"
                    >
                      +
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {localNote.tags &&
                      localNote.tags.map((tag, idx) => (
                        <span
                          key={idx}
                          className="px-3 py-1 bg-gray-200 dark:bg-gray-700 rounded-full text-sm font-semibold text-gray-700 dark:text-gray-300 flex items-center gap-2"
                        >
                          #{tag}
                          <button
                            onClick={() => removeTag(tag)}
                            className="text-red-500 hover:text-red-700"
                          >
                            <X size={14} />
                          </button>
                        </span>
                      ))}
                  </div>
                </div>

                <div>
                  <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-3 flex items-center gap-2">
                    <Palette size={16} />
                    Chọn màu:
                  </p>
                  <div className="grid grid-cols-5 gap-2">
                    {colors.map((color) => (
                      <button
                        key={color.value}
                        onClick={() =>
                          setLocalNote({ ...localNote, color: color.value })
                        }
                        className={`h-10 rounded-lg shadow-md hover:scale-110 transition-transform ${
                          localNote.color === color.value
                            ? "ring-4 ring-blue-500 ring-offset-2"
                            : ""
                        }`}
                        style={{ backgroundColor: color.value }}
                        title={color.name}
                      />
                    ))}
                  </div>
                </div>

                <div className="space-y-3">
                  <label className="flex items-center gap-2 cursor-pointer p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors">
                    <input
                      type="checkbox"
                      checked={localNote.isPinned}
                      onChange={(e) =>
                        setLocalNote({
                          ...localNote,
                          isPinned: e.target.checked,
                        })
                      }
                      className="w-5 h-5"
                    />
                    <Pin size={18} className="text-blue-500" />
                    <span className="font-semibold text-gray-700 dark:text-gray-300">
                      Ghim ghi chú
                    </span>
                  </label>

                  <label className="flex items-center gap-2 cursor-pointer p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors">
                    <input
                      type="checkbox"
                      checked={localNote.isFavorite}
                      onChange={(e) =>
                        setLocalNote({
                          ...localNote,
                          isFavorite: e.target.checked,
                        })
                      }
                      className="w-5 h-5"
                    />
                    <Star size={18} className="text-yellow-500" />
                    <span className="font-semibold text-gray-700 dark:text-gray-300">
                      Yêu thích
                    </span>
                  </label>

                  <label className="flex items-center gap-2 cursor-pointer p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors">
                    <input
                      type="checkbox"
                      checked={localNote.isArchived}
                      onChange={(e) =>
                        setLocalNote({
                          ...localNote,
                          isArchived: e.target.checked,
                        })
                      }
                      className="w-5 h-5"
                    />
                    <Archive size={18} className="text-purple-500" />
                    <span className="font-semibold text-gray-700 dark:text-gray-300">
                      Lưu trữ
                    </span>
                  </label>
                </div>

                <div>
                  <p className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-2">
                    <Bell size={16} />
                    Nhắc nhở:
                  </p>
                  <input
                    type="datetime-local"
                    value={reminderDate}
                    onChange={(e) => {
                      setReminderDate(e.target.value);
                      setLocalNote({
                        ...localNote,
                        reminder: e.target.value ? new Date(e.target.value).toISOString() : null,
                      });
                    }}
                    className="w-full px-3 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none"
                  />
                  {reminderDate && (
                    <button
                      onClick={() => {
                        setReminderDate("");
                        setLocalNote({ ...localNote, reminder: null });
                      }}
                      className="mt-2 text-sm text-red-500 hover:text-red-700"
                    >
                      Xóa nhắc nhở
                    </button>
                  )}
                </div>
              </div>
            </div>

            <button
              onClick={() => {
                const noteToSave = {
                  ...localNote,
                  isMarkdown: isMarkdownMode,
                };
                onSave(noteToSave);
              }}
              className="w-full mt-6 bg-gradient-to-r from-blue-500 to-purple-600 text-white py-4 rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl flex items-center justify-center gap-2"
            >
              <Save size={20} />
              Lưu Ghi Chú
            </button>
          </div>
        </div>
      );
    }
  );

  const StatsModal = React.memo(() => {
    const stats = getStats();
    return (
      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
        <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl max-w-2xl w-full p-8">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <BarChart3 size={28} />
              Thống Kê
            </h2>
            <button
              onClick={() => setShowStats(false)}
              className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
            >
              <X size={24} className="text-gray-600 dark:text-gray-300" />
            </button>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
            <div className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-2xl p-4 text-white">
              <StickyNote size={32} className="mb-2" />
              <p className="text-3xl font-bold">{stats.total}</p>
              <p className="text-sm opacity-90">Tổng số</p>
            </div>
            <div className="bg-gradient-to-br from-yellow-500 to-yellow-600 rounded-2xl p-4 text-white">
              <Star size={32} className="mb-2" />
              <p className="text-3xl font-bold">{stats.favorites}</p>
              <p className="text-sm opacity-90">Yêu thích</p>
            </div>
            <div className="bg-gradient-to-br from-purple-500 to-purple-600 rounded-2xl p-4 text-white">
              <Archive size={32} className="mb-2" />
              <p className="text-3xl font-bold">{stats.archived}</p>
              <p className="text-sm opacity-90">Lưu trữ</p>
            </div>
            <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-2xl p-4 text-white">
              <Pin size={32} className="mb-2" />
              <p className="text-3xl font-bold">{stats.pinned}</p>
              <p className="text-sm opacity-90">Đã ghim</p>
            </div>
          </div>

          <div className="space-y-3">
            <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-4">
              Theo Danh Mục
            </h3>
            {stats.byCategory.map((cat, idx) => (
              <div
                key={idx}
                className="flex items-center justify-between p-3 bg-gray-100 dark:bg-gray-700 rounded-xl"
              >
                <span className="font-semibold text-gray-700 dark:text-gray-300">
                  {cat.name}
                </span>
                <span className="px-3 py-1 bg-blue-500 text-white rounded-full text-sm font-bold">
                  {cat.count}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  });

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 via-purple-50 to-pink-50 dark:from-gray-900 dark:via-gray-800 dark:to-gray-900 flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <div className="text-xl text-gray-600 dark:text-gray-300">
            Đang tải...
          </div>
        </div>
      </div>
    );
  }

  return (
    <div
      className={`min-h-screen ${
        darkMode
          ? "dark bg-gray-900"
          : "bg-gradient-to-br from-blue-50 via-purple-50 to-pink-50"
      }`}
      style={{
        fontSize: userSettings?.customTheme?.fontSize === "small" ? "14px" : userSettings?.customTheme?.fontSize === "large" ? "18px" : "16px",
      }}
    >
      <div className="flex">
        {/* Sidebar */}
        <div
          className={`${
            sidebarOpen ? "w-64" : "w-0"
          } transition-all duration-300 bg-white dark:bg-gray-800 shadow-lg fixed h-full z-30 flex flex-col`}
        >
          <div className="p-6 overflow-y-auto flex-1">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-2">
                <StickyNote size={24} className="text-blue-500" />
                <h2 className="text-xl font-bold text-gray-800 dark:text-white">
                  Menu
                </h2>
              </div>
              <button
                onClick={() => setSidebarOpen(false)}
                className="lg:hidden p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
              >
                <X size={20} />
              </button>
            </div>

            <div className="space-y-2">
              {categories.map((cat) => (
                <button
                  key={cat.id}
                  onClick={() => {
                    setShowTrash(false); // Tắt thùng rác khi chọn category
                    setSelectedCategory(cat.id);
                  }}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all ${
                    selectedCategory === cat.id && !showTrash
                      ? "bg-blue-500 text-white"
                      : "text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700"
                  }`}
                >
                  {cat.icon}
                  <span className="flex-1 text-left">{cat.name}</span>
                  <span className="text-sm opacity-75">
                    {cat.id === "all"
                      ? notes.length
                      : notes.filter((n) => n.category === cat.id || n.category === cat._id).length}
                  </span>
                </button>
              ))}
            </div>

            {/* Custom Categories Section */}
            <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
              <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 mb-2 px-4">
                DANH MỤC TÙY CHỈNH
              </p>
              <CustomCategories
                onCategorySelect={(catId) => setSelectedCategory(catId)}
                selectedCategory={selectedCategory}
                onUpdate={fetchCustomCategories}
              />
            </div>

            <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
              <button
                onClick={() => setShowTemplates(!showTemplates)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all mb-2 ${
                  showTemplates
                    ? "bg-blue-500 text-white"
                    : "text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700"
                }`}
              >
                <FileText size={18} />
                <span>Templates</span>
              </button>
              {showTemplates && (
                <div className="mb-4 p-3 bg-gray-50 dark:bg-gray-700 rounded-lg max-h-64 overflow-y-auto">
                  <Templates
                    onUseTemplate={(note) => {
                      setEditingNote(note);
                      setIsCreating(false);
                      setShowTemplates(false);
                    }}
                  />
                </div>
              )}
            </div>

            <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700 space-y-2">
              <button
                onClick={() => {
                  if (!showTrash) {
                    setSelectedCategory("all"); // Reset category khi mở thùng rác
                    fetchTrash();
                  }
                  setShowTrash(!showTrash);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all ${
                  showTrash
                    ? "bg-red-500 text-white"
                    : "text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700"
                }`}
              >
                <Trash size={18} />
                <span>Thùng rác</span>
                {trashNotes.length > 0 && (
                  <span className="ml-auto bg-white bg-opacity-20 px-2 py-1 rounded-full text-xs">
                    {trashNotes.length}
                  </span>
                )}
              </button>
              <button
                onClick={() => setShowStats(true)}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 transition-all"
              >
                <BarChart3 size={18} />
                <span>Thống kê</span>
              </button>
              <button
                onClick={() => {
                  setShowActivityLog(true);
                  fetchActivities();
                }}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 transition-all"
              >
                <Activity size={18} />
                <span>Nhật ký</span>
              </button>
              <button
                onClick={() => setShowThemeSettings(true)}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 transition-all"
              >
                <Palette size={18} />
                <span>Giao diện</span>
              </button>
              <button
                onClick={() => setDarkMode(!darkMode)}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 transition-all"
              >
                {darkMode ? <Sun size={18} /> : <Moon size={18} />}
                <span>{darkMode ? "Sáng" : "Tối"}</span>
              </button>
              <button
                onClick={logout}
                className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900 transition-all"
              >
                <LogOut size={18} />
                <span>Đăng xuất</span>
              </button>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div
          className={`flex-1 ${
            sidebarOpen ? "lg:ml-64" : "ml-0"
          } transition-all duration-300`}
        >
          {/* Header */}
          <div className="bg-white dark:bg-gray-800 shadow-md sticky top-0 z-20">
            <div className="max-w-7xl mx-auto px-4 py-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                  <button
                    onClick={() => setSidebarOpen(!sidebarOpen)}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors"
                  >
                    <Menu
                      size={24}
                      className="text-gray-700 dark:text-gray-300"
                    />
                  </button>
                  <div className="p-3 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl shadow-lg">
                    <StickyNote size={28} className="text-white" />
                  </div>
                  <div>
                    <h1 className="text-2xl lg:text-3xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
                      Ghi Chú Pro
                    </h1>
                    <p className="text-sm text-gray-500 dark:text-gray-400">
                      {showTrash ? `${trashNotes.length} ghi chú trong thùng rác` : `${filteredNotes.length} ghi chú`}
                      {user && ` • Xin chào, ${user.username}`}
                    </p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() =>
                      document.getElementById("import-file").click()
                    }
                    className="hidden md:flex items-center gap-2 px-4 py-2 bg-green-500 text-white rounded-xl font-semibold hover:bg-green-600 transition-all shadow-lg"
                  >
                    <Upload size={18} />
                    <span className="hidden lg:inline">Nhập</span>
                  </button>
                  <input
                    id="import-file"
                    type="file"
                    accept=".json"
                    onChange={importNotes}
                    className="hidden"
                  />
                  <button
                    onClick={exportNotes}
                    className="hidden md:flex items-center gap-2 px-4 py-2 bg-orange-500 text-white rounded-xl font-semibold hover:bg-orange-600 transition-all shadow-lg"
                  >
                    <Download size={18} />
                    <span className="hidden lg:inline">Xuất</span>
                  </button>
                  <button
                    onClick={() => setIsCreating(true)}
                    className="flex items-center gap-2 px-4 lg:px-6 py-2 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all shadow-lg hover:shadow-xl transform hover:scale-105"
                  >
                    <Plus size={20} />
                    <span className="hidden sm:inline">Tạo Mới</span>
                  </button>
                  <button
                    onClick={performSync}
                    disabled={syncStatus.syncing}
                    className="flex items-center gap-2 px-4 py-2 bg-green-500 text-white rounded-xl font-semibold hover:bg-green-600 transition-all shadow-lg disabled:opacity-50"
                    title="Đồng bộ"
                  >
                    <RefreshCw size={18} className={syncStatus.syncing ? "animate-spin" : ""} />
                  </button>
                </div>
              </div>

              <div className="flex gap-3 mb-4">
                <div className="relative flex-1">
                  <Search
                    className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"
                    size={20}
                  />
                  <input
                    type="text"
                    placeholder="Tìm kiếm ghi chú, thẻ..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-12 pr-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none transition-colors"
                  />
                </div>
                
                {/* Bulk delete controls */}
                {!showTrash && filteredNotes.length > 0 && (
                  <div className="flex gap-2">
                    {selectedNotes.length === 0 ? (
                      <button
                        onClick={selectAllNotes}
                        className="px-4 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-xl font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition-all flex items-center gap-2 whitespace-nowrap"
                        title="Chọn tất cả"
                      >
                        <CheckSquare size={18} />
                        <span className="hidden sm:inline">Chọn tất cả</span>
                      </button>
                    ) : (
                      <>
                        <button
                          onClick={deselectAllNotes}
                          className="px-4 py-3 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-xl font-semibold hover:bg-gray-300 dark:hover:bg-gray-600 transition-all flex items-center gap-2"
                          title="Bỏ chọn"
                        >
                          <X size={18} />
                          <span className="hidden sm:inline">Bỏ chọn</span>
                        </button>
                        <button
                          onClick={deleteSelectedNotes}
                          className="px-4 py-3 bg-red-500 text-white rounded-xl font-semibold hover:bg-red-600 transition-all flex items-center gap-2 shadow-lg hover:shadow-xl"
                          title={`Xóa ${selectedNotes.length} ghi chú`}
                        >
                          <Trash2 size={18} />
                          <span className="hidden sm:inline">Xóa ({selectedNotes.length})</span>
                          <span className="sm:hidden">{selectedNotes.length}</span>
                        </button>
                      </>
                    )}
                  </div>
                )}
              </div>

              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex flex-wrap gap-2">
                  <button
                    onClick={() => setFilterMode("all")}
                    className={`px-3 lg:px-4 py-2 rounded-lg text-sm font-semibold transition-colors flex items-center gap-1 ${
                      filterMode === "all"
                        ? "bg-blue-500 text-white"
                        : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600"
                    }`}
                  >
                    <Filter size={14} />
                    Tất cả
                  </button>
                  <button
                    onClick={() => setFilterMode("active")}
                    className={`px-3 lg:px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
                      filterMode === "active"
                        ? "bg-blue-500 text-white"
                        : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600"
                    }`}
                  >
                    Đang dùng
                  </button>
                  <button
                    onClick={() => setFilterMode("favorites")}
                    className={`flex items-center gap-1 lg:gap-2 px-3 lg:px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
                      filterMode === "favorites"
                        ? "bg-yellow-500 text-white"
                        : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600"
                    }`}
                  >
                    <Star size={16} />
                    <span className="hidden sm:inline">Yêu thích</span>
                  </button>
                  <button
                    onClick={() => setFilterMode("archived")}
                    className={`flex items-center gap-1 lg:gap-2 px-3 lg:px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
                      filterMode === "archived"
                        ? "bg-purple-500 text-white"
                        : "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600"
                    }`}
                  >
                    <Archive size={16} />
                    <span className="hidden sm:inline">Lưu trữ</span>
                  </button>
                </div>

                <div className="flex gap-2">
                  <select
                    value={sortMode}
                    onChange={(e) => setSortMode(e.target.value)}
                    className="px-3 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none text-sm font-semibold"
                  >
                    <option value="date">Mới nhất</option>
                    <option value="updated">Cập nhật gần nhất</option>
                    <option value="title">Tên A-Z</option>
                    <option value="color">Theo màu</option>
                  </select>
                  <button
                    onClick={() =>
                      setViewMode(viewMode === "grid" ? "list" : "grid")
                    }
                    className="p-2 bg-gray-200 dark:bg-gray-700 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
                  >
                    {viewMode === "grid" ? (
                      <List
                        size={20}
                        className="text-gray-700 dark:text-gray-300"
                      />
                    ) : (
                      <Grid
                        size={20}
                        className="text-gray-700 dark:text-gray-300"
                      />
                    )}
                  </button>
                </div>
              </div>
            </div>
          </div>

          {/* Notes Grid/List */}
          <div className="max-w-7xl mx-auto px-4 py-8">
            {showTrash ? (
              trashNotes.length === 0 ? (
                <div className="text-center py-20">
                  <Trash size={64} className="mx-auto text-gray-300 dark:text-gray-600 mb-4" />
                  <p className="text-xl text-gray-500 dark:text-gray-400">Thùng rác trống</p>
                </div>
              ) : (
                <div
                  className={
                    viewMode === "grid"
                      ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                      : "space-y-4"
                  }
                >
                  {trashNotes.map((note) => (
                    <div
                      key={note._id}
                      className="group relative rounded-2xl p-6 shadow-lg bg-gray-100 dark:bg-gray-700"
                    >
                      <h3 className="text-xl font-bold mb-3 text-gray-800 dark:text-white">
                        {note.title}
                      </h3>
                      <p className="text-gray-600 dark:text-gray-300 mb-4 line-clamp-3">
                        {note.content}
                      </p>
                      <div className="flex gap-2">
                        <button
                          onClick={() => restoreNote(note._id)}
                          className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors"
                        >
                          <RotateCcw size={16} />
                          Khôi phục
                        </button>
                        <button
                          onClick={() => deletePermanently(note._id)}
                          className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors"
                        >
                          <Trash2 size={16} />
                          Xóa vĩnh viễn
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )
            ) : filteredNotes.length === 0 ? (
              <div className="text-center py-20">
                <StickyNote
                  size={64}
                  className="mx-auto text-gray-300 dark:text-gray-600 mb-4"
                />
                <p className="text-xl text-gray-500 dark:text-gray-400">
                  {searchTerm
                    ? "Không tìm thấy ghi chú nào"
                    : "Chưa có ghi chú. Hãy tạo ghi chú đầu tiên!"}
                </p>
              </div>
            ) : (
              <div
                className={
                  viewMode === "grid"
                    ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                    : "space-y-4"
                }
              >
                {filteredNotes.map((note) => (
                  <NoteCard key={note._id} note={note} />
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Modals */}
      {isCreating && (
        <NoteModal
          key="create-modal"
          initialNote={defaultNewNote}
          onSave={createNoteFromModal}
          onClose={() => setIsCreating(false)}
          title="Tạo Ghi Chú Mới"
          colors={colors}
          categories={categories}
          customCategories={customCategories}
        />
      )}

      {editingNote && (
        <NoteModal
          key={editingNote._id}
          initialNote={editingNote}
          onSave={updateNoteFromModal}
          onClose={() => setEditingNote(null)}
          title="Chỉnh Sửa Ghi Chú"
          colors={colors}
          categories={categories}
          customCategories={customCategories}
        />
      )}

      {showStats && <StatsModal />}

      {/* Share Modal */}
      {showShareModal && noteToShare && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl max-w-md w-full p-8">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <Share2 size={28} />
                Chia sẻ ghi chú
              </h2>
              <button
                onClick={() => {
                  setShowShareModal(false);
                  setNoteToShare(null);
                  setShareEmail("");
                }}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Email người nhận
                </label>
                <input
                  type="email"
                  value={shareEmail}
                  onChange={(e) => setShareEmail(e.target.value)}
                  placeholder="user@example.com"
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Quyền truy cập
                </label>
                <select
                  value={sharePermission}
                  onChange={(e) => setSharePermission(e.target.value)}
                  className="w-full px-4 py-3 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-xl focus:border-blue-500 focus:outline-none"
                >
                  <option value="read">Chỉ xem</option>
                  <option value="write">Xem và chỉnh sửa</option>
                </select>
              </div>

              <button
                onClick={() => shareNote(noteToShare, shareEmail, sharePermission)}
                className="w-full bg-gradient-to-r from-blue-500 to-purple-600 text-white py-3 rounded-xl font-semibold hover:from-blue-600 hover:to-purple-700 transition-all"
              >
                Chia sẻ
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Versions Modal */}
      {showVersions && selectedNoteForVersions && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl max-w-4xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <History size={28} />
                Lịch sử chỉnh sửa
              </h2>
              <button
                onClick={() => {
                  setShowVersions(false);
                  setSelectedNoteForVersions(null);
                  setNoteVersions([]);
                }}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>

            <div className="space-y-4">
              {noteVersions.length === 0 ? (
                <p className="text-gray-500 dark:text-gray-400 text-center py-8">
                  Chưa có phiên bản nào
                </p>
              ) : (
                noteVersions.map((version, idx) => (
                  <div
                    key={version._id}
                    className="border-2 border-gray-200 dark:border-gray-700 rounded-xl p-4"
                  >
                    <div className="flex items-center justify-between mb-3">
                      <div>
                        <p className="font-semibold text-gray-800 dark:text-white">
                          Phiên bản {version.versionNumber}
                        </p>
                        <p className="text-sm text-gray-500 dark:text-gray-400">
                          {new Date(version.createdAt).toLocaleString("vi-VN")}
                        </p>
                      </div>
                      <button
                        onClick={() => restoreVersion(selectedNoteForVersions, version._id)}
                        className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors flex items-center gap-2"
                      >
                        <RotateCcw size={16} />
                        Khôi phục
                      </button>
                    </div>
                    <div className="mt-3">
                      <p className="font-semibold mb-2">{version.title}</p>
                      <p className="text-sm text-gray-600 dark:text-gray-300 line-clamp-3">
                        {version.content}
                      </p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {/* Activity Log Modal */}
      {showActivityLog && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl max-w-4xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <Activity size={28} />
                Nhật ký hoạt động
              </h2>
              <button
                onClick={() => setShowActivityLog(false)}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>

            <div className="space-y-2">
              {activities.length === 0 ? (
                <p className="text-gray-500 dark:text-gray-400 text-center py-8">
                  Chưa có hoạt động nào
                </p>
              ) : (
                activities.map((activity) => (
                  <div
                    key={activity._id}
                    className="p-4 border border-gray-200 dark:border-gray-700 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    <div className="flex items-start justify-between">
                      <div className="flex-1">
                        <p className="font-semibold text-gray-800 dark:text-white">
                          {activity.action === "note_created" && "Đã tạo ghi chú"}
                          {activity.action === "note_updated" && "Đã cập nhật ghi chú"}
                          {activity.action === "note_deleted" && "Đã xóa ghi chú"}
                          {activity.action === "note_restored" && "Đã khôi phục ghi chú"}
                          {activity.action === "note_shared" && "Đã chia sẻ ghi chú"}
                          {activity.action === "template_used" && "Đã sử dụng template"}
                          {activity.action === "category_created" && "Đã tạo danh mục"}
                          {activity.action === "settings_updated" && "Đã cập nhật cài đặt"}
                        </p>
                        {activity.details?.title && (
                          <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
                            {activity.details.title}
                          </p>
                        )}
                        <p className="text-xs text-gray-500 dark:text-gray-500 mt-2">
                          {new Date(activity.createdAt).toLocaleString("vi-VN")}
                        </p>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {/* Theme Settings Modal */}
      {showThemeSettings && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-2xl max-w-2xl w-full p-8 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <Palette size={28} />
                Tùy chỉnh giao diện
              </h2>
              <button
                onClick={() => setShowThemeSettings(false)}
                className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              >
                <X size={24} className="text-gray-600 dark:text-gray-300" />
              </button>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Màu chính
                </label>
                <div className="flex items-center gap-4">
                  <input
                    type="color"
                    value={userSettings?.customTheme?.primaryColor || "#3b82f6"}
                    onChange={async (e) => {
                      const updated = {
                        ...userSettings,
                        customTheme: {
                          ...(userSettings?.customTheme || {}),
                          primaryColor: e.target.value,
                        },
                      };
                      setUserSettings(updated);
                      // Apply ngay lập tức
                      document.documentElement.style.setProperty("--primary-color", e.target.value);
                      try {
                        await fetch(`${API_URL}/settings`, {
                          method: "PUT",
                          headers: getAuthHeaders(),
                          body: JSON.stringify(updated),
                        });
                      } catch (error) {
                        console.error("Lỗi cập nhật theme:", error);
                      }
                    }}
                    className="w-20 h-12 rounded-lg cursor-pointer"
                  />
                  <span className="text-sm text-gray-600 dark:text-gray-400">
                    {userSettings?.customTheme?.primaryColor || "#3b82f6"}
                  </span>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Màu phụ
                </label>
                <div className="flex items-center gap-4">
                  <input
                    type="color"
                    value={userSettings?.customTheme?.secondaryColor || "#8b5cf6"}
                    onChange={async (e) => {
                      const updated = {
                        ...userSettings,
                        customTheme: {
                          ...(userSettings?.customTheme || {}),
                          secondaryColor: e.target.value,
                        },
                      };
                      setUserSettings(updated);
                      // Apply ngay lập tức
                      document.documentElement.style.setProperty("--secondary-color", e.target.value);
                      try {
                        await fetch(`${API_URL}/settings`, {
                          method: "PUT",
                          headers: getAuthHeaders(),
                          body: JSON.stringify(updated),
                        });
                      } catch (error) {
                        console.error("Lỗi cập nhật theme:", error);
                      }
                    }}
                    className="w-20 h-12 rounded-lg cursor-pointer"
                  />
                  <span className="text-sm text-gray-600 dark:text-gray-400">
                    {userSettings?.customTheme?.secondaryColor || "#8b5cf6"}
                  </span>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Font size
                </label>
                <select
                  value={userSettings?.customTheme?.fontSize || "medium"}
                  onChange={async (e) => {
                    const fontSizeMap = { small: "14px", medium: "16px", large: "18px" };
                    const updated = {
                      ...userSettings,
                      customTheme: {
                        ...(userSettings?.customTheme || {}),
                        fontSize: e.target.value,
                      },
                    };
                    setUserSettings(updated);
                    // Apply ngay lập tức
                    document.documentElement.style.setProperty("--font-size", fontSizeMap[e.target.value]);
                    try {
                      await fetch(`${API_URL}/settings`, {
                        method: "PUT",
                        headers: getAuthHeaders(),
                        body: JSON.stringify(updated),
                      });
                    } catch (error) {
                      console.error("Lỗi cập nhật theme:", error);
                    }
                  }}
                  className="w-full px-4 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none"
                >
                  <option value="small">Nhỏ (14px)</option>
                  <option value="medium">Vừa (16px)</option>
                  <option value="large">Lớn (18px)</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                  Card Style
                </label>
                <select
                  value={userSettings?.customTheme?.cardStyle || "elevated"}
                  onChange={async (e) => {
                    const updated = {
                      ...userSettings,
                      customTheme: {
                        ...(userSettings?.customTheme || {}),
                        cardStyle: e.target.value,
                      },
                    };
                    setUserSettings(updated);
                    try {
                      await fetch(`${API_URL}/settings`, {
                        method: "PUT",
                        headers: getAuthHeaders(),
                        body: JSON.stringify(updated),
                      });
                    } catch (error) {
                      console.error("Lỗi cập nhật theme:", error);
                    }
                  }}
                  className="w-full px-4 py-2 border-2 border-gray-200 dark:border-gray-600 dark:bg-gray-700 dark:text-white rounded-lg focus:border-blue-500 focus:outline-none"
                >
                  <option value="flat">Phẳng</option>
                  <option value="elevated">Nổi</option>
                  <option value="outlined">Viền</option>
                </select>
              </div>

              <div className="pt-4 border-t border-gray-200 dark:border-gray-700">
                <button
                  onClick={async () => {
                    // Reset về mặc định
                    const defaultTheme = {
                      primaryColor: "#3b82f6",
                      secondaryColor: "#8b5cf6",
                      fontSize: "medium",
                      cardStyle: "elevated",
                    };
                    const updated = {
                      ...userSettings,
                      customTheme: defaultTheme,
                    };
                    setUserSettings(updated);
                    // Reset CSS
                    document.documentElement.style.setProperty("--primary-color", defaultTheme.primaryColor);
                    document.documentElement.style.setProperty("--secondary-color", defaultTheme.secondaryColor);
                    document.documentElement.style.setProperty("--font-size", "16px");
                    try {
                      await fetch(`${API_URL}/settings`, {
                        method: "PUT",
                        headers: getAuthHeaders(),
                        body: JSON.stringify(updated),
                      });
                    } catch (error) {
                      console.error("Lỗi reset theme:", error);
                    }
                  }}
                  className="w-full px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors font-semibold"
                >
                  Đặt lại mặc định
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Sync Status Indicator */}
      {syncStatus.syncing && (
        <div className="fixed bottom-4 right-4 bg-blue-500 text-white px-4 py-2 rounded-lg shadow-lg flex items-center gap-2 z-40">
          <RefreshCw size={16} className="animate-spin" />
          <span>Đang đồng bộ...</span>
        </div>
      )}
    </div>
  );
};

export default NotesApp;
